/**
 * This is a modal that "pauses" a nanoflow and shows a modal which requires a user to provide an input.
 * 
 * The only function this action currently does is take the input from a user. It will show the value in a toast alert if the Show Success option is set to TRUE.
 * 
 * Modify this script to meet your specific needs.
 * @param {string} label
 * @param {string} validationMessage - The message to display if value not entered.
 * @param {boolean} showSuccess - Set to TRUE to show a success toast.
 * @param {"SweetAlert2.ENUM_SweetAlert2_InputType.checkbox"|"SweetAlert2.ENUM_SweetAlert2_InputType.email"|"SweetAlert2.ENUM_SweetAlert2_InputType.number"|"SweetAlert2.ENUM_SweetAlert2_InputType.password"|"SweetAlert2.ENUM_SweetAlert2_InputType.tel"|"SweetAlert2.ENUM_SweetAlert2_InputType.radio"|"SweetAlert2.ENUM_SweetAlert2_InputType.range"|"SweetAlert2.ENUM_SweetAlert2_InputType.select"|"SweetAlert2.ENUM_SweetAlert2_InputType.text"|"SweetAlert2.ENUM_SweetAlert2_InputType.textarea"|"SweetAlert2.ENUM_SweetAlert2_InputType.url"} inputType - Type of input to render. Should match the specified attribute type.
 * @returns {Promise.<void>}
 */
export async function JS_ShowModal_UserInput(label, validationMessage, showSuccess, inputType) {
	// BEGIN USER CODE
	const { value: inputValue } = await Swal.fire({
  		title: label,
  		input: inputType,
  		showCancelButton: true,
  		inputValidator: (value) => {
    		if (!value) {
      			return validationMessage
    		}
  		}
	});

	if (inputValue) {
		const Toast = Swal.mixin({
			toast: true,
			position: 'bottom',
			showConfirmButton: false,
			showCloseButton: true,
			timer: 3000,
			timerProgressBar: true,
			onOpen: (toast) => {
				toast.addEventListener('mouseenter', Swal.stopTimer)
				toast.addEventListener('mouseleave', Swal.resumeTimer)
			}
		});

		if (showSuccess) {
			Toast.fire({
				icon: 'success',
				title: 'You entered: "' + inputValue + '"!'
			});
		}
	}
	// END USER CODE
}
